const Q_PHYSICS_2025_MODEL_I=[{"id": "objective>Physics>2025 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the phenomenon where a wave changes direction as it passes from one medium to another?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interference</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Refraction occurs when a wave (such as light or sound) passes from one medium into another (e.g., air to water) and changes direction due to a change in its speed. This bending of the wave at the interface between the two media is called refraction.</div>", "topic": "REFRACTION OF LIGHT THROUGH AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2025 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A balloon contains 10,000 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of air at 27°C and 760 mmHg. If the balloon is released and rises to an altitude where the temperature is -23°C and the pressure is 380 mmHg, what will be its new volume? Assume ideal gas behavior.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10,500.50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12,250.00 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">13,333.33 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">16,666.67 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10000 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>; T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27°C + 273 = 300 K;  <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 760 mmHg; T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = -23°C + 273 = 250 K; P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 380 mmHg; <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/>  <br/> To find the new volume of the balloon at the new altitude, we can use the combined gas law, which relates pressure, volume, and temperature: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">760 × 10,000<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">380V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />250</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">760 × 10,000 × 250<hr size=\"1\" />380 × 300</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1,900,000,000<hr size=\"1\" />114,000</td></tr></table></div> <br/> ∴ V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 16,666.67 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2025 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 3 V cell drives 0.5 A through a circuit. If the internal resistance is 1 Ω, what is the resistance of the external load?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E = 3 V; I = 0.5 A; r = 1 Ω; R = ? <br/>  <br/> E = V + Ir <br/>  <br/> V = E - Ir <br/>  <br/> V = 3 - 0.5 × 1 <br/>  <br/> V = 3 - 0.5 <br/>  <br/> V = 2.5 V <br/>  <br/> From Ohm's Law: <br/>  <br/> V = IR <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />I</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.5<hr size=\"1\" />0.5</td></tr></table></div> <br/> ∴ R = 5 Ω</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2025 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 2.0 kg block of a metal alloy with a specific heat capacity of 400 J/kg°C is heated by a 500 W heater for 2 minutes. Assuming no heat loss to the surroundings, what is the final temperature of the block if its initial temperature was 20°C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">95°C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = 2.0 kg; c = 400 J/kg°C; P = 500 W; θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20°C; <br/>  <br/> t = 2 min = 120 s; θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/>  <br/> Pt = mc∆θ <br/>  <br/> 500 × 120 = 2 × 400 × (θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - 20) <br/>  <br/> 60000 = 800(θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - 20) <br/>  <br/> 60000 = 800θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - 16000 <br/>  <br/> 60000 + 16000 = 800θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> 76000 = 800θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">76000<hr size=\"1\" />800</td></tr></table></div> <br/> ∴ θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 95°C</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2025 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about waves is true?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Waves cannot transfer energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waves require a medium to travel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All waves are transverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waves transfer energy without transferring matter</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Waves are disturbances that propagate through a medium or vacuum, transferring energy from one point to another. <br/>  <br/> During this propagation, particles in the medium oscillate about their mean positions but do not travel with the wave. Hence, matter is not transferred, only energy is. <br/>  <br/> This applies to both mechanical waves (like sound, water) and electromagnetic waves (like light, radio).</div>", "topic": "WAVE: PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2025 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car is traveling at 90 km/h. The driver sees a hazard and applies the brakes, decelerating at a rate of 5.0 m/s². What is the distance the car travels before coming to a stop?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">112.5 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">62.5 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25 m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Initial</td><td style=\"text-align:center;\">velocity,</td><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90</td><td style=\"text-align:center;\">km/h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90 × 1000<hr size=\"1\" />3600</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25</td><td style=\"text-align:center;\">m/s</td></tr></table></div> <br/> Final velocity, v = 0m/s (since the car comes to a stop) <br/>  <br/> Acceleration, a = −5.0m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> (negative because it's deceleration) <br/>  <br/> Distance, s = ? <br/>  <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as <br/>  <br/> 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2(-5)s <br/>  <br/> 0 = 625 - 10s <br/>  <br/> 10s = 625 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">625<hr size=\"1\" />10</td></tr></table></div> <br/> ∴ s = 62.5 m</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2025 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon by which sound waves bend around obstacles is called:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interference</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diffraction is the phenomenon where sound waves bend around the edges of obstacles or openings. This is why you can hear someone speaking even when they are not in your direct line of sight.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2025 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 10 Ω resistor carries a current of 2 A. What is the power dissipated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60 W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80 W</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The power dissipated in a resistor is proportional to the square of the current flowing through it, multiplied by its resistance. This is a basic application of Joule's law of heating. <br/>  <br/> Mathematically, P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R <br/>  <br/> Given: <br/>  <br/> R = 10 Ω <br/>  <br/> I = 2 A <br/>  <br/> P = 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 10 <br/>  <br/> P = 4 × 10 <br/>  <br/> ∴ P = 40 W</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2025 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A crane lifts a 1000 kg crate from the ground to a height of 15 m in 30 seconds. What is the average power of the crane?  <br/>  <br/> (Take g = 9.8 m/s²)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.8 KW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.9 KW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 KW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.1 KW</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> m = 1000 kg <br/>  <br/> h = 15 m <br/>  <br/> t = 30 s <br/>  <br/> g = 9.8 m/s² <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mgh<hr size=\"1\" />t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1000 × 9.8 × 15<hr size=\"1\" />30</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">147000<hr size=\"1\" />30</td></tr></table></div> <br/> ∴ P = 4900 W = 4.9 KW</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2025 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rocket moves in space by expelling gas. This motion is best explained by:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Newton's First Law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Newton's Second Law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Newton's Third Law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Law of Conservation of Mass</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Newton's Third Law states that \"For every action, there is an equal and opposite reaction.\" When a rocket expels gas backward, the equal and opposite reaction propels the rocket forward. This is the fundamental principle behind rocket propulsion. While Newton's First and Second Laws are important in understanding motion and force, it is specifically the Third Law that explains how rockets move in space where no external force or atmosphere is present.</div>", "topic": "MOTION: NEWTON'S LAWS OF MOTION"}, {"id": "objective>Physics>2025 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A thermometer has a scale that is linear with the resistance of a wire. The resistance of the wire is 50 Ω at the ice point 0°C and 90 Ω at the steam point 100°C. What is the temperature when the resistance is 70 Ω?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80°C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 50 Ω <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">100</span> = 90 Ω <br/>  <br/> R = 70 Ω <br/>  <br/> C = ? <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C - 0<hr size=\"1\" />100 - 0</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R - R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">100</span> - R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">70 - 50<hr size=\"1\" />90 - 50</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />40</td></tr></table></div> <br/> 40C = 2000 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000<hr size=\"1\" />40</td></tr></table></div> <br/> ∴ C = 50°C</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2025 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wave pulse is sent down a string that is fixed at one end. When the pulse reaches the fixed end, it will be <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflected and inverted.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not reflected and absorbed.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflected but not inverted.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflected and its speed increases.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a wave pulse travels down a string and hits a fixed end, it reflects back. However, due to the fixed boundary, the wave inverts upon reflection. This is a fundamental property of wave behavior at boundaries: <br/>  <br/> A fixed end causes the reflected wave to be inverted (i.e., undergoes a 180° phase shift). <br/>  <br/> A free end would reflect the wave without inversion.</div>", "topic": "WAVE: CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2025 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 2.0 kg block is attached to a string and swung in a vertical circle of radius 0.5 m. What is the minimum speed of the block at the top of the circle to ensure the string remains taut? (Take g = 9.8 m/s²).</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.89 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.21 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.13 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.72 m/s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> m = 2.0 kg <br/> r = 0.5 m <br/> g = 9.8 m/s² <br/>  <br/> To ensure the string remains taut at the top of the circle, the tension in the string must be at least zero. At this point, the centripetal force is provided entirely by the weight of the block, so we equate: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mg</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.8</td></tr></table></div> <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 9.8 × 0.5 <br/>  <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 4.9 <br/>  <br/> v = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">4.9&nbsp;</span> <br/>  <br/> ∴ v = 2.21 m/s</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2025 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block with an initial speed of 10 m/s slides on a horizontal surface and comes to rest after traveling a distance of 25 m. What is the coefficient of kinetic friction between the block and the surface? (Take g = 9.8 m/s²).</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> u = 10 m/s <br/> v = 0 m/s <br/> s = 25 m <br/> g = 9.8 m/s² <br/> μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span> = ? <br/>  <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as <br/>  <br/> 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2a(25) <br/>  <br/> 0 = 100 + 50a <br/>  <br/> 50a = -100 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-100<hr size=\"1\" />50</td></tr></table></div> <br/> a = -2 m/s² <br/>  <br/> The only horizontal force causing deceleration is friction, so: <br/>  <br/> f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">friction</span> = ma <br/>  <br/> μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span>R = ma <br/>  <br/> μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span>mg = ma (∵ R = mg) <br/>  <br/> μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span>g = a <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">a<hr size=\"1\" />g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />9.8</td></tr></table></div> <br/> ∴ μ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span> = 0.2</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2025 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why does a person perceive a metal surface to feel colder than a wooden surface, even when both are at the same temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The metal has a higher thermal conductivity than the wood.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The metal has a higher specific heat capacity than the wood.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The metal has a higher temperature than the wood, despite reading the same on a thermometer.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The metal radiates more heat than the wood.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metal feels colder because it has a much higher thermal conductivity, which means it draws heat away from your skin more quickly than wood does. This rapid transfer of heat from your body gives the sensation of coldness, even though both materials are at the same temperature.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2025 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A U-tube initially contains water in both arms. Oil with a density of 800 kg/m³ is poured into the left arm until the oil column reaches a height of 0.25 m. What is the height of the water column in the right arm relative to the original water level? <br/>  <br/> (Density of water = 1000 kg/m³)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.10 m above</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.15 m above</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20 m above</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25 m above</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Density of water (ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>) = 1000 kg/m³ <br/> Density of oil (ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>) = 800 kg/m³ <br/> Height of oil column (h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>) = 0.25 m <br/>  <br/> The oil in the left arm exerts a pressure of P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span>gh<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span>. <br/>  <br/> This pressure is balanced by the extra water column (h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span>​) in the right arm: <br/>  <br/> ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span>gh<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span>gh<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span> <br/>  <br/> So, <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span><hr size=\"1\" />ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oil</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">800<hr size=\"1\" />1000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.25</td></tr></table></div> <br/> h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span> = 0.8 × 0.25 <br/>  <br/> ∴ h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span> = 0.20 m <br/>  <br/> Thus, the water in the right arm rises by 0.20 m above the original level.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2025 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs represent one scalar and one vector quantity respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Distance and mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Speed and velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Work and energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force and temperature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Speed is a scalar quantity – it has only magnitude (how fast something is moving), no direction. <br/>  <br/> Velocity is a vector quantity – it has both magnitude and direction (how fast and in which direction something is moving). <br/>  <br/> Distance and mass: Both are scalars. <br/>  <br/> Work and energy: Both are scalars. <br/>  <br/> Force and temperature: Force is a vector, but temperature is a scalar</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2025 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements correctly describes the gravitational potential near a massive object?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is maximum (least negative) at the surface of the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is zero at an infinite distance from the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It becomes less negative as the distance from the object decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a vector quantity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gravitational potential (V) at a point is defined as the work done per unit mass to move a test mass from an infinite distance to that point. The conventional zero potential energy reference point is set at an infinite distance from the massive object. The formula for gravitational potential is given by:  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">−GM<hr size=\"1\" />r​</td></tr></table></div> <br/> As the distance r approaches infinity, the potential V approaches zero.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2025 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform beam PQ, 10 m long and of mass 20 kg, is supported at both ends. A mass of 40 kg is suspended at a point 4 m from end P. Find the reactions at the supports P and Q. <br/> (Take g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P = 280 N, Q = 320 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = 320 N, Q = 280 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = 260 N, Q = 340 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = 340 N, Q = 260 N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2025 Model I/YF8BMN.png\" style=\"position:relative;max-width:100%;\"/> <br/> weight of beam PQ = 20 × 10 = 200 N <br/>  <br/> load = 40 × 10 = 400 N <br/>  <br/> Sum of upward forces = Sum of downward forces <br/>  <br/> P + Q = 400 + 200 <br/>  <br/> P + Q = 600 N ----- (i) <br/>  <br/> Sum of anticlockwise moments = Sum of clockwise moments <br/>  <br/> Taking moment at P: <br/>  <br/> Q × 10 = 400 × 4 + 200 × 5 <br/>  <br/> 10Q = 1600 + 1000 <br/>  <br/> 10Q = 2600 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2600<hr size=\"1\" />10</td></tr></table></div> <br/> Q = 260 N <br/>  <br/> From equation (i) <br/>  <br/> P + 260 = 600 <br/>  <br/> P = 600 - 260 <br/>  <br/> P = 340 N</div>", "topic": "EQUILIBRIUM OF FORCES: CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2025 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The least count of a vernier caliper is 0.01 cm. What does this imply?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It can measure up to 1 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can measure the smallest object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can measure lengths up to 0.01 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can measure with a precision of 0.01 cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The least count of an instrument is the smallest length it can accurately measure. <br/>  <br/> A vernier caliper with a least count of 0.01 cm means it can distinguish changes in length as small as 0.01 cm (or 0.1 mm).</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2025 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is placed 7 cm in front of a concave mirror of focal length 3.5 cm. The image will be:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Virtual, erect, and magnified</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Real, inverted, and magnified</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Real, inverted, and same size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Virtual, erect, and diminished</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> u = 7 cm <br/> f = 3.5 cm <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />3.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />7</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />7</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />7</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />7</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />7</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />7</td></tr></table></div> <br/> v = +7 cm <br/>  <br/> The image distance is 7 cm. The positive sign indicates that the image is formed on the same side of the mirror as the object, which means the image is real. <br/>  <br/> Since the image is at 2f, magnification is 1 (same size as the object). </div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2025 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A student is viewing an object through a compound microscope. The distance between the objective and the eyepiece is increased. What happens to the final image?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The magnification of the objective lens decreases.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The magnification of the eyepiece increases.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The final image moves closer to the eyepiece.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The final image is no longer in focus for the observer.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a compound microscope, the image formation involves two lenses: <br/>  <br/> The objective lens forms a real, inverted, and magnified image of the object, somewhere inside the microscope tube. <br/>  <br/> The eyepiece lens then magnifies this real image to produce the final virtual image observed by the eye. <br/>  <br/> What happens if the distance between the objective and the eyepiece increases? <br/>  <br/> The relative position of the intermediate image (formed by the objective) and the focal point of the eyepiece changes. <br/>  <br/> This causes the final image to become out of focus. <br/>  <br/> Unless the observer adjusts the focusing mechanism, the image will appear blurred or displaced, and not clearly visible.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2025 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform electric field of 20 N/C exists in the positive x-direction. What is the potential difference between a point at x = 10 m and a point at x = 5 m?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60 V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To solve this problem, we apply the relationship between electric field and electric potential difference: <br/>  <br/> ΔV = −E⋅Δx  <br/>  <br/> Given: <br/>  <br/> Electric field, E=20 N/C (in the positive x-direction) <br/>  <br/> x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10 m, x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 5 m <br/>  <br/> So, Δx = x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> − x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 5 − 10 = −5 m <br/>  <br/> ∴ ΔV = −(20)⋅(−5) = +100 V</div>", "topic": "ELECTROSTATICS: COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2025 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A straight wire of mass 200 g and length 1.5 m carries a current of 2.0 A. The wire is suspended in a uniform magnetic field in a way that the magnetic force exactly balances the gravitational force on the wire. The direction of the magnetic field is horizontal and perpendicular to the wire. What is the magnitude of the magnetic field? <br/>  <br/> (Take g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25 T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50 T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.65 T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.85 T</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We are given: <br/> Mass of the wire, m = 200 g = 0.2 kg <br/> Length of the wire, L = 1.5 m <br/> Current through the wire, I = 2.0 A <br/> Acceleration due to gravity, g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> Gravitational force: F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = mg <br/>  <br/> Magnetic force: F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = BIL <br/>  <br/> At equilibrium: F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> ​ <br/>  <br/> 0.2 × 9.8 = B × 2 × 1.5 <br/>  <br/> 1.96 = 3B <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">B</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.96<hr size=\"1\" />3</td></tr></table></div> <br/> ∴ B = 0.65 T</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2025 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes the reason shadows form sharp edges under direct sunlight?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Light is absorbed by the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Light is a particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Light travels in straight lines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The object is opaque</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shadows form sharp edges under direct sunlight because light travels in straight lines. When light from a point source (like the Sun) is blocked by an object, it cannot bend around the object, leading to a well-defined (sharp-edged) shadow.</div>", "topic": "LIGHT ENERGY: PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2025 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two resistors, R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> ​= 3 Ω and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ​= 6 Ω, are connected in parallel. This combination is then connected in series with a third resistor, R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> ​= 4 Ω. If a voltage of 20 V is applied across the entire circuit, what is the current flowing through the 6 Ω resistor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.33 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.67 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.11 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.83 A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2025 Model I/JTNLWF.png\" style=\"position:relative;max-width:100%;\"/> <br/> The equivalent resistance of the parallel combination: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 + 1<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> = 2 Ω <br/>  <br/> Total resistance in the circuit: <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Total</span> = R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 2 + 4 <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Total</span> = 6 Ω <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Total</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Total</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Total</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />3</td><td style=\"text-align:center;\">A</td><td style=\"text-align:center;\">≈</td><td style=\"text-align:center;\">3.33</td><td style=\"text-align:center;\">A</td></tr></table></div> <br/> Voltage across the parallel combination: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Total</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />3</td><td style=\"text-align:center;\">V</td></tr></table></div> <br/> Current through the 6 Ω resistor: <br/>  <br/> In a parallel combination, voltage is the same across all components: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</td><td style=\"text-align:center;\">Ω</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />3</td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />18</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</td><td style=\"text-align:center;\">Ω</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />9</td><td style=\"text-align:center;\">≈</td><td style=\"text-align:center;\">1.11</td><td style=\"text-align:center;\">A</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2025 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about magnetic field lines is incorrect?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They always form closed loops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They emerge from the north pole and enter the south pole externally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They intersect at points where fields are strongest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their density represents field strength</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The incorrect statement is \"They intersect at points where fields are strongest <br/> \" because magnetic field lines never intersect, as this would imply two directions of the magnetic field at the same point, which is physically impossible, unlike the other statements which correctly describe how magnetic field lines form closed loops, emerge from the north and enter the south externally, and have a density that indicates field strength.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2025 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is it easier to open a door by pushing at the edge farthest from the hinge?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It reduces the effect of the door's mass.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The friction at the hinges decreases with distance.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It gives a bigger moment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It makes the door to have less inertia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The moment (or turning effect) is the product of force and perpendicular distance from the pivot. Pushing farther from the hinge increases this distance, thus increasing the moment and making the door easier to open.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2025 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle performs S.H.M. with an amplitude of 10 cm and a period of 2.0 s. What is the magnitude of its acceleration when its displacement from the equilibrium position is 6.0 cm?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.12 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.35 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.59 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.99 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> A = 10 cm = 0.1 m <br/> x = 6.0 cm = 0.06 m <br/> T = 2.0 s <br/> a = ? <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ω</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">π</td><td style=\"text-align:center;\">rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div> <br/> We take the magnitude only, so we drop the negative sign: <br/>  <br/> a = ω<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>x = π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 0.06 <br/>  <br/> ∴ a = 0.59 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2025 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wheel and axle has a wheel radius of 50 cm and an axle radius of 10 cm. The efficiency of the machine is 60%. What is the effort required to lift a load of 500 N?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">154.71 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">162.50 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">166.67 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">186.33 N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Radius of wheel, R = 50 cm <br/> Radius of axle, r = 10 cm <br/> Load, L = 500N <br/> Efficiency, E = 60% <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">VR</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<hr size=\"1\" />r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100%</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60%</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100%</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />5</td></tr></table></div> <br/> M.A = 0.6 × 5 <br/>  <br/> M.A = 3 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<hr size=\"1\" />E</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />E</td></tr></table></div> <br/> 3E = 500 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />3</td></tr></table></div> <br/> ∴ E = 166.67 N</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2025 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is true regarding the dispersion of light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Violet light deviates the most and red light deviates the least when passing through a prism.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The refractive index of a medium is the same for all colours of light.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion is independent of the refractive index of the material.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The speed of light in a vacuum is different for different colours.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When white light passes through a prism, it splits into its constituent colours because each colour has a different wavelength and thus a different refractive index in the medium, causing violet light (shorter wavelength) to slow down more and bend the most, while red light (longer wavelength) bends the least, which is the principle of dispersion that leads to the formation of a visible spectrum.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2025 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ancient wooden artifact is found to have <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">8</span> the amount of carbon-14 as a fresh sample of wood. The half-life of carbon-14 is 5730 years. What is the age of the artifact?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">28650 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22920 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11460 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17190 years</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Final amount = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">8</span> of the original amount <br/> Half-life of Carbon-14 = 5730 years <br/>  <br/> Each half-life reduces the amount of C-14 to half: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">After</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">half-life</td><td style=\"text-align:center;\">→</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">After</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">half-lives</td><td style=\"text-align:center;\">→</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">After</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">half-lives</td><td style=\"text-align:center;\">→</td><td style=\"text-align:center;\">1<hr size=\"1\" />8</td></tr></table></div> <br/> So, it has gone through 3 half-lives. <br/>  <br/> ∴ Age = 3 × half-life = 3 × 5730 = 17190 years ​</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2025 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two wires, one of steel and one of copper, are of the same length and cross-sectional area. They are stretched by the same force. If Young's modulus for steel is twice that of copper, what is the ratio of the extension of the steel wire to the extension of the copper wire?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To solve this, we'll use the formula for extension in a wire under a given force using Hooke's Law: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />AY</td></tr></table></div> <br/> Where: <br/>  <br/> e = extension <br/>  <br/> F = applied force <br/>  <br/> L = original length <br/>  <br/> A = cross-sectional area <br/>  <br/> Y = Young's modulus of the material <br/>  <br/> Given: <br/>  <br/> Same F, L, and A for both wires <br/>  <br/> Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">steel</span> = 2Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">copper</span> <br/>  <br/> Let's denote: <br/>  <br/> e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = extension in steel <br/>  <br/> e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = extension in copper <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />2AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span>,</td><td style=\"text-align:center;\">e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td></tr></table></div> <br/> Now, we take the ratio: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />2AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">FL<hr size=\"1\" />AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />2AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">AY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span><hr size=\"1\" />FL</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">:</td><td style=\"text-align:center;\">2</td></tr></table></div></div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2025 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The critical temperature of a gas is the temperature:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Above which it cannot be liquefied, regardless of the pressure applied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At which the average kinetic energy of molecules becomes zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At which the gas behaves ideally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Below which the gas cannot exist in a gaseous state</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The critical temperature of a substance is the highest temperature at which it can be liquefied by applying pressure. <br/>  <br/> Above this temperature, the kinetic energy of the molecules is so high that no amount of pressure can bring them close enough to form a liquid. <br/>  <br/> Therefore, a gas cannot be liquefied above its critical temperature, no matter how much pressure is applied.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY: MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2025 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A photoelectric surface has a work function of 4.0 eV. Light of wavelength 200 nm is incident on the surface. What is the maximum kinetic energy of the emitted photoelectrons? <br/>  <br/> (h = 6.63 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> Js, c = 3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, 1 eV = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> J)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.18 eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.22 eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.94 eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.11 eV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 4.0 eV <br/> λ = 200 nm = 200 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−9</span> m <br/> h = 6.63 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> J  <br/> c = 3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/> c = fλ <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">c<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />200 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−9</span></td></tr></table></div> <br/> f = 1.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span> Hz <br/>  <br/> E = hf = 6.63 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> × 1.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span> <br/>  <br/> E = 9.945 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> J <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.945 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span><hr size=\"1\" />1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td><td style=\"text-align:center;\">eV</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.22</td><td style=\"text-align:center;\">eV</td></tr></table></div> <br/> K.E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span> = E - W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 6.22 - 4.0 <br/>  <br/> ∴ K.E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span> = 2.22 eV</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2025 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrochemical equivalent (Z) of a substance is 0.00112 g/C. What current will deposit 2.24 g of the substance in 10 minutes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.33 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.67 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00 A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Z = 0.00112 g/C <br/> m = 2.24 g <br/> t = 10 mins = 10 × 60 s = 600 s <br/>  <br/> m = ZIt <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />Zt</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.24<hr size=\"1\" />0.00112 × 600</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.24<hr size=\"1\" />0.672</td></tr></table></div> <br/> ∴ I = 3.33 A</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2025 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrostatic force between two charges is considered a conservative force because:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It depends on velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It causes friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The work done is path-independent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It only acts at a distance</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A conservative force is one for which the work done in moving an object between two points is independent of the path taken. Electrostatic force fits this description because: <br/>  <br/> When a charge moves in an electric field created by another charge, the work done only depends on the initial and final positions, not the path taken. <br/>  <br/> This means that if a charged particle returns to its starting point after moving through an electric field, the net work done by the electrostatic force is zero, which is a key property of conservative forces.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2025 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is the speed of sound independent of amplitude?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Because sound is a linear wave</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Because amplitude is always constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Because it depends only on frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Because of inverse square law</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a linear medium (like air for small amplitudes), the speed of sound depends only on the properties of the medium (e.g., temperature, density, elasticity) and not on the wave's amplitude. <br/>  <br/> The wave equation for sound is linear, meaning superposition holds, and amplitude cancels out in the speed calculation.</div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2025 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens during electrical breakdown of a gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gas turns solid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas becomes supercooled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas suddenly becomes conductive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas loses all electrons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrical breakdown of a gas occurs when the electric field applied across the gas exceeds a critical value, causing the gas atoms or molecules to ionize. This ionization creates free electrons and positive ions. The electrons are accelerated by the electric field, collide with other gas atoms, and cause further ionization in a chain reaction. As a result, the gas, normally an insulator, becomes conductive and allows a large current to pass through — this is seen as a spark or discharge (e.g., lightning or neon light glow). <br/>  <br/> This phenomenon is the basis of gas discharge tubes, lightning, and spark plugs.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2025 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about nuclear fusion is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It produces long-lived radioactive waste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is currently widely used in power plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It requires lower temperatures than fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It produces more energy per nucleon than fission</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear fusion (e.g., combining hydrogen isotopes into helium) releases more energy per nucleon than nuclear fission (e.g., splitting uranium-235). This is because fusion involves light nuclei forming a more tightly bound nucleus, leading to a greater mass-to-energy conversion.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}];
